/**
 * Bucket 5 UVIX/SVIX insurance backtest panel (etf-dashboard).
 * Loads data/bucket5_insurance_backtest.json generated by scripts/build_bucket5_insurance_backtest.py
 */
(function (root, factory) {
  if (typeof module === 'object' && module.exports) {
    module.exports = factory(require('react'));
  } else {
    root.Bucket5InsuranceBacktest = factory(root.React);
  }
})(typeof self !== 'undefined' ? self : this, function (React) {
  const { useState, useEffect, useMemo } = React;

  const DATA_URL = 'data/bucket5_insurance_backtest.json';

  function fmtPct(n, d) {
    if (n == null || Number.isNaN(n)) return '—';
    return (n * 100).toFixed(d == null ? 1 : d) + '%';
  }

  function fmtUsd(n) {
    if (n == null || Number.isNaN(n)) return '—';
    const s = Math.abs(n).toLocaleString(undefined, { maximumFractionDigits: 0 });
    return (n < 0 ? '-$' : '$') + s;
  }

  function seriesPath(series, w, h, pad, transform) {
    if (!series || series.length < 2) return '';
    const ys = series.map((pt) => transform(Number(pt[1])));
    const minY = Math.min(...ys);
    const maxY = Math.max(...ys);
    const span = maxY - minY || 1;
    return series
      .map((pt, i) => {
        const x = pad + (i / (series.length - 1)) * (w - 2 * pad);
        const y = h - pad - ((transform(Number(pt[1])) - minY) / span) * (h - 2 * pad);
        return `${x.toFixed(1)},${y.toFixed(1)}`;
      })
      .join(' ');
  }

  function DualChart({ title, equity, drawdown }) {
    const w = 680;
    const hEq = 150;
    const hDd = 80;
    const pad = 10;
    const eqPts = seriesPath(equity, w, hEq, pad, (v) => v / 1e6);
    const ddPts = seriesPath(drawdown, w, hDd, pad, (v) => v * 100);
    return React.createElement(
      'div',
      { className: 'b5-ins-chart', style: { marginBottom: 16 } },
      React.createElement('h3', { style: { fontSize: 14, marginBottom: 8, color: 'var(--text-secondary)' } }, title),
      React.createElement(
        'svg',
        { viewBox: `0 0 ${w} ${hEq + hDd + 16}`, width: '100%', style: { maxWidth: w } },
        React.createElement('text', { x: pad, y: 14, fill: 'var(--text-muted)', fontSize: 11 }, 'Equity ($M)'),
        React.createElement('polyline', { fill: 'none', stroke: '#10b981', strokeWidth: 2, points: eqPts }),
        React.createElement('line', { x1: pad, y1: hEq + 8, x2: w - pad, y2: hEq + 8, stroke: 'var(--border)' }),
        React.createElement('text', { x: pad, y: hEq + 22, fill: 'var(--text-muted)', fontSize: 11 }, 'Drawdown (%)'),
        React.createElement('polyline', {
          fill: 'none',
          stroke: '#ef4444',
          strokeWidth: 1.2,
          transform: `translate(0,${hEq + 8})`,
          points: ddPts,
        }),
      ),
    );
  }

  function MetricCard({ label, value, accent }) {
    return React.createElement(
      'div',
      { className: 'summary-card', style: { minWidth: 120 } },
      React.createElement('div', { className: 'label', style: { fontSize: 11, color: 'var(--text-muted)' } }, label),
      React.createElement(
        'div',
        { style: { fontSize: 20, fontWeight: 700, fontFamily: 'JetBrains Mono', color: accent || 'var(--text-primary)' } },
        value,
      ),
    );
  }

  function Bucket5InsurancePage({ onBack, onNavigateToChart }) {
    const [payload, setPayload] = useState(null);
    const [error, setError] = useState(null);
    const [variantKey, setVariantKey] = useState('F_extended');
    const [compareKey, setCompareKey] = useState('B_extended');

    useEffect(() => {
      let cancelled = false;
      fetch(`${DATA_URL}?t=${Math.floor(Date.now() / 60000)}`, { cache: 'no-store' })
        .then((r) => {
          if (!r.ok) throw new Error(`HTTP ${r.status}`);
          return r.json();
        })
        .then((d) => {
          if (!cancelled) setPayload(d);
        })
        .catch((e) => {
          if (!cancelled) setError(e.message || 'load failed');
        });
      return () => {
        cancelled = true;
      };
    }, []);

    const variants = useMemo(() => (payload && payload.variants) || {}, [payload]);
    const keys = Object.keys(variants);
    const v = variants[variantKey] || variants[keys[0]];
    const cmp = compareKey ? variants[compareKey] : null;

    if (error) {
      return React.createElement(
        'div',
        { className: 'backtest-page' },
        React.createElement('button', { type: 'button', className: 'topbar-btn', onClick: onBack }, '← Back'),
        React.createElement('p', { style: { color: 'var(--accent-red)', marginTop: 16 } }, `Bucket 5 backtest unavailable: ${error}`),
        React.createElement(
          'p',
          { style: { color: 'var(--text-muted)', fontSize: 13, marginTop: 8 } },
          'Run: python scripts/build_bucket5_insurance_backtest.py (requires ls-algo sibling checkout).',
        ),
      );
    }

    if (!payload || !v) {
      return React.createElement(
        'div',
        { className: 'backtest-page' },
        React.createElement('p', { style: { padding: 24, color: 'var(--text-muted)' } }, 'Loading Bucket 5 insurance backtest…'),
      );
    }

    const m = v.metrics || {};
    return React.createElement(
      'div',
      { className: 'backtest-page' },
      React.createElement(
        'div',
        { style: { display: 'flex', alignItems: 'center', gap: 12, marginBottom: 16, flexWrap: 'wrap' } },
        React.createElement('button', { type: 'button', className: 'topbar-btn', onClick: onBack }, '← Back'),
        React.createElement('h2', { style: { fontSize: 18 } }, 'Bucket 5 — UVIX/SVIX Insurance Backtest'),
        React.createElement(
          'span',
          { style: { fontSize: 11, color: 'var(--text-muted)', fontFamily: 'JetBrains Mono' } },
          `as of ${payload.run_date || '—'}`,
        ),
      ),
      React.createElement(
        'p',
        { style: { fontSize: 13, color: 'var(--text-secondary)', marginBottom: 16, maxWidth: 900 } },
        'Short UVIX + short SVIX carry sleeve (regime gates, ~14d cadence) with SPX put hedge, T-bill collateral, and liquidate-and-redeploy monetization. ',
        'Interactive parameter lab: ',
        React.createElement('code', null, payload.lab_command || 'streamlit run scripts/bucket5_lab.py'),
        ' in ls-algo.',
      ),
      React.createElement(
        'div',
        { className: 'backtest-controls', style: { marginBottom: 16 } },
        React.createElement(
          'label',
          { className: 'backtest-control' },
          'Variant ',
          React.createElement(
            'select',
            { value: variantKey, onChange: (e) => setVariantKey(e.target.value) },
            keys.map((k) =>
              React.createElement('option', { key: k, value: k }, `${variants[k].label || k} (${variants[k].era})`),
            ),
          ),
        ),
        React.createElement(
          'label',
          { className: 'backtest-control', style: { marginLeft: 12 } },
          'Compare ',
          React.createElement(
            'select',
            { value: compareKey, onChange: (e) => setCompareKey(e.target.value) },
            React.createElement('option', { value: '' }, '— none —'),
            keys.map((k) =>
              React.createElement('option', { key: k, value: k }, `${variants[k].label || k} (${variants[k].era})`),
            ),
          ),
        ),
        React.createElement(
          'button',
          { type: 'button', className: 'topbar-btn', style: { marginLeft: 12 }, onClick: () => onNavigateToChart && onNavigateToChart('UVIX') },
          'Chart UVIX',
        ),
        React.createElement(
          'button',
          { type: 'button', className: 'topbar-btn', style: { marginLeft: 6 }, onClick: () => onNavigateToChart && onNavigateToChart('SVIX') },
          'Chart SVIX',
        ),
      ),
      React.createElement(
        'div',
        { className: 'summary-strip', style: { display: 'flex', gap: 12, flexWrap: 'wrap', marginBottom: 20 } },
        React.createElement(MetricCard, { label: 'CAGR', value: fmtPct(m.combined_CAGR), accent: 'var(--accent-green)' }),
        React.createElement(MetricCard, { label: 'Vol', value: fmtPct(m.combined_Vol) }),
        React.createElement(MetricCard, { label: 'Max DD', value: fmtPct(m.combined_MaxDD), accent: 'var(--accent-red)' }),
        React.createElement(MetricCard, { label: 'Sharpe', value: m.combined_Sharpe == null ? '—' : Number(m.combined_Sharpe).toFixed(2) }),
        React.createElement(MetricCard, { label: 'Realized $', value: fmtUsd(m['realized_$']) }),
        React.createElement(MetricCard, { label: 'Redeploy $', value: fmtUsd(m['redeploy_extra_$']) }),
      ),
      React.createElement(DualChart, {
        title: v.label || variantKey,
        equity: (v.series || {}).combined_equity || [],
        drawdown: (v.series || {}).drawdown || [],
      }),
      cmp &&
        React.createElement(DualChart, {
          title: (cmp.label || compareKey) + ' (compare)',
          equity: (cmp.series || {}).combined_equity || [],
          drawdown: (cmp.series || {}).drawdown || [],
        }),
      React.createElement(
        'h3',
        { style: { fontSize: 14, margin: '12px 0 8px' } },
        'Stylized crash payoffs',
      ),
      React.createElement(
        'table',
        { className: 'data-table', style: { fontSize: 13, maxWidth: 480 } },
        React.createElement(
          'thead',
          null,
          React.createElement('tr', null, React.createElement('th', null, 'Scenario'), React.createElement('th', null, 'Combined P&L')),
        ),
        React.createElement(
          'tbody',
          null,
          Object.entries(v.crash || {}).map(([k, val]) =>
            React.createElement('tr', { key: k }, React.createElement('td', null, k), React.createElement('td', null, fmtPct(val))),
          ),
        ),
      ),
      React.createElement(
        'p',
        { style: { fontSize: 11, color: 'var(--text-muted)', marginTop: 16 } },
        `Borrow UVIX ${fmtPct((v.assumptions || {}).borrow_uvix_annual, 2)}/yr · SVIX ${fmtPct((v.assumptions || {}).borrow_svix_annual, 2)}/yr · `,
        `slippage ${(v.assumptions || {}).uvix_slip_bps || '—'} bps · pricing ${(v.meta || {}).pricing_mode || '—'} · `,
        `${(v.meta || {}).start || ''} → ${(v.meta || {}).end || ''}`,
      ),
    );
  }

  return { Bucket5InsurancePage, DATA_URL };
});
